<?php
require_once __DIR__.'/../../config.php';redirect_if_not_logged_in();mb_require_any_permission($pdo,['view_estimates','manage_estimates']);require_once __DIR__.'/../_shared/workspace.php';ensure_maorin_workspace_tables($pdo);$can=current_user_can($pdo,'manage_estimates');$projects=mb_project_options($pdo);$edit=null;
function mb_est_totals($l,$m,$e,$o,$mk,$tx){$sub=$l+$m+$e+$o;$mark=$sub*($mk/100);$tax=($sub+$mark)*($tx/100);return[$sub,$mark,$tax,$sub+$mark+$tax];}
if($_SERVER['REQUEST_METHOD']==='POST'&&$can){try{csrf_verify();$a=$_POST['action']??'';if($a==='save'){$id=(int)($_POST['id']??0);$l=(float)$_POST['labor_cost'];$m=(float)$_POST['material_cost'];$eq=(float)$_POST['equipment_cost'];$o=(float)$_POST['overhead_cost'];$mk=(float)$_POST['markup_percent'];$tx=(float)$_POST['tax_percent'];[$sub,$mark,$tax,$grand]=mb_est_totals($l,$m,$eq,$o,$mk,$tx);$data=[$_POST['project_id']?:null,trim($_POST['estimate_no']??''),trim($_POST['title']??''),trim($_POST['client_name']??''),trim($_POST['status']??'draft'),$l,$m,$eq,$o,$mk,$tx,$sub,$mark,$tax,$grand,trim($_POST['notes']??'')];if($data[2]==='')throw new RuntimeException('Title required.');if($id){$pdo->prepare("UPDATE mb_estimates SET project_id=?,estimate_no=?,title=?,client_name=?,status=?,labor_cost=?,material_cost=?,equipment_cost=?,overhead_cost=?,markup_percent=?,tax_percent=?,subtotal=?,markup_amount=?,tax_amount=?,grand_total=?,notes=? WHERE id=?")->execute([...$data,$id]);mb_set_success('Estimate updated.');}else{$pdo->prepare("INSERT INTO mb_estimates (project_id,estimate_no,title,client_name,status,labor_cost,material_cost,equipment_cost,overhead_cost,markup_percent,tax_percent,subtotal,markup_amount,tax_amount,grand_total,notes,created_by) VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)")->execute([...$data,(int)$_SESSION['user_id']]);mb_set_success('Estimate created.');}}elseif($a==='delete'){$pdo->prepare("DELETE FROM mb_estimates WHERE id=?")->execute([(int)$_POST['id']]);mb_set_success('Estimate deleted.');}}catch(Throwable $e){mb_set_error($e->getMessage());}mb_redirect('index.php');}
if(isset($_GET['edit'])){$st=$pdo->prepare("SELECT * FROM mb_estimates WHERE id=?");$st->execute([(int)$_GET['edit']]);$edit=$st->fetch(PDO::FETCH_ASSOC);} $rows=$pdo->query("SELECT e.*,p.name project_name FROM mb_estimates e LEFT JOIN mb_projects p ON p.id=e.project_id ORDER BY e.updated_at DESC,e.id DESC")->fetchAll(PDO::FETCH_ASSOC);[$ok,$err]=mb_flash();mb_workspace_header($pdo,'Estimates','Estimates'); ?>
<?php if($ok):?><div class="alert alert-success"><?=htmlspecialchars($ok)?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?=htmlspecialchars($err)?></div><?php endif;?><div class="mb-card"><div class="mb-card-header"><div><strong>Construction estimates</strong><div class="text-muted small">Labor, materials, equipment, overhead, markup, tax, and grand total.</div></div><?php if($can):?><button class="btn btn-primary" data-mb-open-modal="estimateModal">New Estimate</button><?php endif;?></div><div class="table-responsive"><table class="table mb-table"><thead><tr><th>No.</th><th>Title</th><th>Project</th><th>Client</th><th>Status</th><th>Subtotal</th><th>Markup</th><th>Tax</th><th>Total</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><?=htmlspecialchars($r['estimate_no']?:$r['id'])?></td><td><strong><?=htmlspecialchars($r['title'])?></strong></td><td><?=htmlspecialchars($r['project_name']?:'-')?></td><td><?=htmlspecialchars($r['client_name'])?></td><td><span class="mb-badge"><?=htmlspecialchars($r['status'])?></span></td><td>₱<?=mb_money($r['subtotal'])?></td><td>₱<?=mb_money($r['markup_amount'])?></td><td>₱<?=mb_money($r['tax_amount'])?></td><td><strong>₱<?=mb_money($r['grand_total'])?></strong></td><td class="mb-actions"><?php if($can):?><a class="btn btn-sm btn-outline-primary" href="?edit=<?=(int)$r['id']?>">Edit</a><form method="post"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=(int)$r['id']?>"><button class="btn btn-sm btn-outline-danger" data-confirm="Delete estimate?">Delete</button></form><?php endif;?></td></tr><?php endforeach;if(!$rows):?><tr><td colspan="10" class="text-center text-muted py-4">No estimates yet.</td></tr><?php endif;?></tbody></table></div></div><div class="modal fade" id="estimateModal"><div class="modal-dialog modal-xl"><form method="post" class="modal-content mb-modal-panel"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=(int)($edit['id']??0)?>"><div class="modal-header"><h5 class="modal-title"><?=$edit?'Edit':'New'?> Estimate</h5><button class="btn-close" type="button" data-bs-dismiss="modal"></button></div><div class="modal-body"><div class="mb-form-grid"><label>Project<select class="form-select" name="project_id"><option value="">No project</option><?php foreach($projects as $p):?><option value="<?=(int)$p['id']?>" <?=((int)($edit['project_id']??0)===(int)$p['id']?'selected':'')?>><?=htmlspecialchars($p['name'])?></option><?php endforeach;?></select></label><label>Estimate No.<input class="form-control" name="estimate_no" value="<?=htmlspecialchars($edit['estimate_no']??'')?>"></label><label>Title<input required class="form-control" name="title" value="<?=htmlspecialchars($edit['title']??'')?>"></label><label>Client<input class="form-control" name="client_name" value="<?=htmlspecialchars($edit['client_name']??'')?>"></label><label>Status<input class="form-control" name="status" value="<?=htmlspecialchars($edit['status']??'draft')?>"></label><label>Labor<input class="form-control" type="number" step="0.01" name="labor_cost" value="<?=htmlspecialchars($edit['labor_cost']??'0')?>"></label><label>Materials<input class="form-control" type="number" step="0.01" name="material_cost" value="<?=htmlspecialchars($edit['material_cost']??'0')?>"></label><label>Equipment<input class="form-control" type="number" step="0.01" name="equipment_cost" value="<?=htmlspecialchars($edit['equipment_cost']??'0')?>"></label><label>Overhead<input class="form-control" type="number" step="0.01" name="overhead_cost" value="<?=htmlspecialchars($edit['overhead_cost']??'0')?>"></label><label>Markup %<input class="form-control" type="number" step="0.01" name="markup_percent" value="<?=htmlspecialchars($edit['markup_percent']??'0')?>"></label><label>Tax %<input class="form-control" type="number" step="0.01" name="tax_percent" value="<?=htmlspecialchars($edit['tax_percent']??'0')?>"></label><label class="full">Notes<textarea class="form-control" name="notes"><?=htmlspecialchars($edit['notes']??'')?></textarea></label></div></div><div class="modal-footer"><button class="btn btn-primary">Save Estimate</button></div></form></div></div><script><?php if($edit):?>new bootstrap.Modal(document.getElementById('estimateModal')).show();<?php endif;?></script><?php mb_workspace_footer(); ?>